// Twisted, perforated pen / utensil holder tower
// v.sdf is the STAR: a hollow rounded-square tube has a CLEAN GRID of windows
// punched clean through the wall (wall.subtract(hole.repeatN(...))), then the
// whole wall is warped with .twist about Z, welded to a SOLID flat base slab
// and a SOLID lavender top rim ring.
// Two-tone via labels: violet body, lighter-lavender top rim.
const { voxels, sdf } = api;
const v = voxels();

const VIOLET = '#7c5cff';
const LAVENDER = '#c0b3ff';

// --- dimensions (world units ~ mm) ---
const W = 40;        // footprint x/y
const H = 85;        // total height
const t = 5;         // wall thickness (thin enough holes punch fully through, >=2 voxel struts remain)
const r = 6;         // outer corner rounding
const twistDeg = 120; // total twist bottom -> top
const rate = twistDeg / H; // deg per unit along z

const baseH = 7;     // solid base slab
const rimH = 6;      // solid top rim ring

// --- Hollow square tube (the wall annulus), open top & bottom ---
const outer = sdf.roundedBox([W, W, H], r);
const inner = sdf.box([W - 2 * t, W - 2 * t, H + 12]); // tall -> punches through top/bottom
const tube = outer.subtract(inner);

// --- Punch a clean grid of square windows clean through the wall. ---
// A single hole node, deep on X so it cuts fully through both the +X and -X
// faces; tiled in a grid across Z (and Y so the rotation about Z carries it to
// all four faces). Big openings (window ~9mm) with ~4mm solid struts between.
const win = 8;       // window size (square-ish) -> ~8mm, clearly see-through
const wallDepth = t + 6; // cut depth per face: through the t=5 wall, no further
const pitchZ = 18;   // vertical pitch -> ~10mm SOLID band between window rows
const pitchY = 11;   // lateral pitch (unused at cols=1)
const rows = 4;      // window rows up the tower
const cols = 1;      // one window centered on each face per row
const faceR = W / 2; // distance from center to a face

// One face's grid of windows: a small rounded box, repeated as a cols×rows grid,
// then pushed OUT to a face so it cuts only that wall (depth = wallDepth, so the
// deep cuts never reach the opposite wall or the corner struts).
function faceWindows(axis) {
  // axis 'x' -> cut depth along X; windows spread along Y (cols) and Z (rows).
  // axis 'y' -> cut depth along Y; windows spread along X (cols) and Z (rows).
  const boxSize = axis === 'x' ? [wallDepth, win, win] : [win, wallDepth, win];
  const step = axis === 'x' ? [0, pitchY, pitchZ] : [pitchY, 0, pitchZ];
  const count = axis === 'x' ? [1, cols, rows] : [cols, 1, rows];
  const grid = sdf.roundedBox(boxSize, 1.2).repeatN(step, count);
  const plus = axis === 'x' ? grid.translate(faceR, 0, 0) : grid.translate(0, faceR, 0);
  const minus = axis === 'x' ? grid.translate(-faceR, 0, 0) : grid.translate(0, -faceR, 0);
  return sdf.union(plus, minus);
}
const holes = sdf.union(faceWindows('x'), faceWindows('y'));

const wall = tube.subtract(holes).twist(rate, 'z').label('body');

// --- Solid lavender rim ring at the TOP. Built/positioned at its real z then
// twisted with the SAME rate -> its twist phase (rate*rimZ) matches the wall top,
// so they weld cleanly. Kept as its own labeled node so it stays lavender. ---
const rimZ = H / 2 - rimH / 2;
const rimOuter = sdf.roundedBox([W, W, rimH], 2).translate(0, 0, rimZ);
const rimInner = sdf.box([W - 2 * t, W - 2 * t, rimH + 12]).translate(0, 0, rimZ);
const rim = rimOuter.subtract(rimInner).twist(rate, 'z').label('rim');

// --- Solid flat base slab flush at the bottom (NOT twisted -> clean flat square
// that sits flat on the bed and welds to the bottom of the twisted wall). ---
const baseZ = -H / 2 + baseH / 2;
const base = sdf.box([W, W, baseH]).round(3).translate(0, 0, baseZ).label('body');

const model = sdf.union(wall, rim, base);

v.sdf(model, {
  res: 1,
  color: VIOLET,
  colors: { body: VIOLET, rim: LAVENDER },
  bounds: { min: [-W / 2 - 3, -W / 2 - 3, -H / 2 - 2], max: [W / 2 + 3, W / 2 + 3, H / 2 + 2] },
});

// --- One-piece weld: drop any stray specks the perforation left behind. ---
v.keepLargest();

return v;
